     1→import {
     2→  BackDropBottom,
     3→  Box,
     4→  Button,
     5→  ChooseButton,
     6→  Text,
     7→} from '@semparar/design-system-app';
     8→import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
     9→import React, { FC, useCallback, useEffect, useMemo, useState } from 'react';
    10→import { Dimensions } from 'react-native';
    11→import { eventSelectContent } from '~/constants/functions';
    12→import { FilterOption, TYPE_LABELS, TransactionType } from '../../../services';
    13→
    14→interface FilterGroup {
    15→  label: string;
    16→  options: FilterOption[];
    17→}
    18→
    19→interface FiltersBottomSheetProps {
    20→  modalizeRef: React.RefObject<PropsModalizeRef>;
    21→  filterGroups: FilterGroup[];
    22→  onApplyFilters: (filters: any) => void;
    23→  initialFilters?: any;
    24→}
    25→
    26→interface MemoizedFilterGroupProps {
    27→  group: FilterGroup;
    28→  groupIndex: number;
    29→  selectedIndex: number | undefined;
    30→  filterItems: Array<{
    31→    id: number;
    32→    title: string;
    33→  }>;
    34→  onFilterChange: (
    35→    groupIndex: number,
    36→    options: FilterOption[],
    37→  ) => (item: any, index: number | number[]) => void;
    38→}
    39→
    40→const MemoizedFilterGroup = React.memo<MemoizedFilterGroupProps>(({
    41→  group,
    42→  groupIndex,
    43→  selectedIndex,
    44→  filterItems,
    45→  onFilterChange,
    46→}) => {
    47→  const filterChangeHandler = onFilterChange(groupIndex, group.options);
    48→
    49→  return (
    50→    <Box>
    51→      <Text
    52→        type="paragraphXL"
    53→        color="INTENSE_COLOR_05"
    54→        mt={groupIndex === 0 ? 'xxxs' : 'xxs'}
    55→        ml="small"
    56→        mb="xxxs"
    57→      >
    58→        {group.label}
    59→      </Text>
    60→
    61→      <ChooseButton
    62→        items={filterItems}
    63→        type="select"
    64→        ml="small"
    65→        numColumns={3}
    66→        selectMultipleItems={false}
    67→        defaultOption={selectedIndex}
    68→        onPress={filterChangeHandler}
    69→      />
    70→    </Box>
    71→  );
    72→});
    73→
    74→const FiltersBottomSheet: FC<FiltersBottomSheetProps> = ({
    75→  modalizeRef,
    76→  filterGroups,
    77→  onApplyFilters,
    78→  initialFilters = {},
    79→}) => {
    80→  const [selectedFilters, setSelectedFilters] =
    81→    useState<Record<number, any>>(initialFilters);
    82→
    83→  const screenWidth = useMemo(() => Dimensions.get('window').width, []);
    84→
    85→  useEffect(() => {
    86→    setSelectedFilters(initialFilters);
    87→  }, [initialFilters]);
    88→
    89→  const filterItemsMap = useMemo(() => {
    90→    return filterGroups.map(group =>
    91→      group.options.map((option, idx) => ({
    92→        id: idx,
    93→        title: option.label,
    94→      })));
    95→  }, [filterGroups]);
    96→
    97→  const selectedIndices = useMemo(() => {
    98→    return filterGroups.map((group, groupIndex) => {
    99→      const selectedValue = selectedFilters[groupIndex];
   100→
   101→      if (selectedValue === undefined) {
   102→        return undefined;
   103→      }
   104→
   105→      const index = group.options.findIndex(opt => opt.value === selectedValue);
   106→      return index >= 0 ? index : undefined;
   107→    });
   108→  }, [
   109→    filterGroups,
   110→    selectedFilters,
   111→  ]);
   112→
   113→  const handleFilterChange = useCallback((
   114→    groupIndex: number,
   115→    options: FilterOption[],
   116→  ) => {
   117→    return (_item: number, index: number | number[]) => {
   118→      const selectedIndex = Array.isArray(index) ? index[0] : index;
   119→      if (selectedIndex !== undefined && selectedIndex >= 0) {
   120→        const value = options[selectedIndex].value;
   121→
   122→        setSelectedFilters(prev => {
   123→          const currentValue = prev[groupIndex];
   124→          const newValue = currentValue === value ? undefined : value;
   125→          return {
   126→            ...prev,
   127→            [groupIndex]: newValue,
   128→          };
   129→        });
   130→      }
   131→    };
   132→  }, []);
   133→
   134→  const handleClear = useCallback(() => {
   135→    modalizeRef.current?.close?.();
   136→
   137→    setTimeout(() => {
   138→      setSelectedFilters({});
   139→      onApplyFilters({});
   140→    }, 100);
   141→  }, [
   142→    onApplyFilters,
   143→    modalizeRef,
   144→  ]);
   145→
   146→  const handleApply = useCallback(() => {
   147→    const filtersToApply = selectedFilters;
   148→    const period = filtersToApply[0];
   149→    const type = filtersToApply[1];
   150→
   151→    const contentIdParts = ['filtrar'];
   152→    if (period) contentIdParts.push(String(period));
   153→    if (type) {
   154→      const typeLabel = TYPE_LABELS[type as TransactionType] || type;
   155→      contentIdParts.push(typeLabel.toLowerCase());
   156→    }
   157→
   158→    const contentId = contentIdParts.join('_').toLowerCase();
   159→
   160→    eventSelectContent({
   161→      content_type: 'cta',
   162→      content_id: contentId,
   163→      location_1: 'monetizacao',
   164→      location_2: 'hub_recompensas_spmais',
   165→      location_3: 'filtro_extrato_hub',
   166→    });
   167→
   168→    modalizeRef.current?.close?.();
   169→
   170→    setTimeout(() => {
   171→      onApplyFilters(filtersToApply);
   172→    }, 100);
   173→  }, [
   174→    selectedFilters,
   175→    onApplyFilters,
   176→    modalizeRef,
   177→  ]);
   178→
   179→  return (
   180→    <BackDropBottom modalizeRef={modalizeRef} pd="none">
   181→      <Box mt="xxs">
   182→        <Box>
   183→          {filterGroups.map((group, groupIndex) => (
   184→            <MemoizedFilterGroup
   185→              key={groupIndex}
   186→              group={group}
   187→              groupIndex={groupIndex}
   188→              selectedIndex={selectedIndices[groupIndex]}
   189→              filterItems={filterItemsMap[groupIndex]}
   190→              onFilterChange={handleFilterChange}
   191→            />
   192→          ))}
   193→        </Box>
   194→
   195→        <Box mt="small" direction width={screenWidth} ml="small">
   196→          <Button
   197→            text="Limpar"
   198→            width={screenWidth * 0.43}
   199→            type="secundaryMedium"
   200→            onPress={handleClear}
   201→          />
   202→          <Button
   203→            width={screenWidth * 0.43}
   204→            text="Filtrar"
   205→            type="primaryMedium"
   206→            ml="xs"
   207→            onPress={handleApply}
   208→          />
   209→        </Box>
   210→      </Box>
   211→    </BackDropBottom>
   212→  );
   213→};
   214→
   215→export default FiltersBottomSheet;
   216→

